insert into practice_context_blocks (id, exercise_id, label, image_url, text_content, block_type) values
  ('d0e4a14c-13d3-4eb4-a9a0-954bd9fcd1b2', '70be6b12-9de2-4133-b696-e1d12f4893d4', $$indigo — oplosbaarheid en figuur 1 (structuurformule)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2023-ii-indigo-context1.png$$,
   $$Jaarlijks worden drie miljoen spijkerbroeken geproduceerd, die zijn gekleurd met het blauwe pigment indigo (zie figuur 1). Indigo wordt door extractie gewonnen uit de indigoplant. Indigo is slecht oplosbaar in water, met een maximale oplosbaarheid van 1,0 mg L⁻¹.

figuur 1: structuurformule van indigo — twee benzeenringen elk gefuseerd met een vijfring; de vijfringen zijn met elkaar verbonden via een C=C-binding. Op de linker vijfring zitten een C=O-groep en een N–H-groep, op de rechter vijfring eveneens een N–H-groep en een C=O-groep (symmetrisch).$$, 'inline'),
  ('81614ba7-7f4f-46a0-8285-841141138d6b', '70be6b12-9de2-4133-b696-e1d12f4893d4', $$indigo vlak molecuul — premisse VSEPR-vraag$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2023-ii-indigo-context2.png$$,
   $$Een molecuul indigo is vlak. Dit kan alleen worden verklaard als alle mogelijke grensstructuren worden meegenomen in de redenering. Op basis van figuur 1 zou de conclusie moeten zijn dat een indigomolecuul niet vlak is.$$, 'inline'),
  ('fd0b27bc-7b5f-427d-b458-dbad7b1f59c8', '70be6b12-9de2-4133-b696-e1d12f4893d4', $$grensstructuren indigo — formele ladingen (premisse vraag 3)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2023-ii-indigo-context3.png$$,
   $$Van indigo zijn veel grensstructuren mogelijk. De O-atomen hebben hierbij telkens een negatieve formele lading. De positieve formele ladingen kunnen daarbij op elk atoom in de beide vijfringen terechtkomen. Op de uitwerkbijlage is de lewisstructuur van zo'n grensstructuur onvolledig weergegeven. In deze lewisstructuur zijn de formele ladingen geplaatst, maar ontbreekt een aantal elektronenparen.$$, 'inline'),
  ('eb4dd0b7-3a97-4347-8805-2520e1a713a0', '70be6b12-9de2-4133-b696-e1d12f4893d4', $$uitwerkbijlage vraag 3 — onvolledige lewisstructuur grensstructuur indigo$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2023-ii-indigo-context4.png$$,
   $$uitwerkbijlage bij vraag 3: een grensstructuur van indigo met formele ladingen al aangegeven (O⁻ links-boven, N⁺H rechts-boven, benzeenring links met +, N–H links-onder, O⁻ rechts-onder), maar zonder de bindende en niet-bindende elektronenparen — deze moet de kandidaat toevoegen.$$, 'uitwerkbijlage'),
  ('469df439-4248-4b25-9389-79ab4d851795', '70be6b12-9de2-4133-b696-e1d12f4893d4', $$slechte oplosbaarheid indigo — twee factoren (premisse vraag 4)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2023-ii-indigo-context5.png$$,
   $$De slechte oplosbaarheid van indigo kan worden verklaard vanuit de structuur van het molecuul. Er spelen hierbij twee factoren een rol:
1. Er bestaan onderlinge interacties tussen atomen/atoomgroepen binnen een molecuul indigo, waardoor deze atomen/atoomgroepen minder goed interacties met watermoleculen kunnen aangaan.
2. Delen van het molecuul kunnen alleen zwakke interacties aangaan met watermoleculen.$$, 'inline'),
  ('a51164b7-b399-4e03-bdb2-72c165e70805', '70be6b12-9de2-4133-b696-e1d12f4893d4', $$figuur 2 — indigowit (reductie van indigo)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2023-ii-indigo-context6.png$$,
   $$Indigo wordt na extractie uit de indigoplant eerst met een reductor omgezet tot het oplosbare indigowit (zie figuur 2). Opgelost indigowit wordt tijdens het verven van katoen opgezogen door de katoenvezels.

figuur 2: structuurformule van indigowit — dezelfde dubbele-vijfring-structuur als indigo, maar nu met HO- en OH-groepen op de plaats van de C=O-groepen (de C=C-binding tussen de vijfringen blijft behouden).$$, 'inline'),
  ('05121a00-af1e-4e49-8e48-d2b2cd2f52cb', '70be6b12-9de2-4133-b696-e1d12f4893d4', $$histidine naar alanine — inactivering enzym UGT (premisse vraag 6)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2023-ii-indigo-context7.png$$,
   $$Als eerste werd het actieve centrum van één van de betrokken enzymen (het enzym UGT) in de plant onderzocht. De onderzoekers vermoedden dat een histidine-eenheid in het enzym UGT een rol speelt bij de koppeling van glucose aan indoxyl. Om dit te onderzoeken vervingen de onderzoekers, door genetische modificatie van het DNA, deze histidine-eenheid door een alanine-eenheid. Deze vervanging maakte het enzym UGT inderdaad inactief.$$, 'inline'),
  ('9e7c63e2-6e36-4a32-8d79-b26725533ffe', '70be6b12-9de2-4133-b696-e1d12f4893d4', $$figuur 3 — vorming van indigo in de plant (FMO, UGT, BGL)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2023-ii-indigo-context8.png$$,
   $$In figuur 3 is de vorming van indigo in de plant schematisch weergegeven. Drie betrokken enzymen zijn met de afkortingen FMO, UGT en BGL aangegeven.

figuur 3: tryptofaan → indool → (FMO) → indoxyl → (+ glucose, UGT) → indicaan (opgeslagen). Bij beschadiging: indicaan → (+ glucose, BGL) → indoxyl → (O₂, spontaan) → indigo.$$, 'inline'),
  ('8150f4e9-eea0-4a69-a226-932ed82a6e23', '70be6b12-9de2-4133-b696-e1d12f4893d4', $$pad indool–indoxyl–indicaan–indigo in het blad$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2023-ii-indigo-context9.png$$,
   $$In het blad van de indigoplant wordt indool door het enzym FMO omgezet tot indoxyl. In aanwezigheid van het enzym UGT wordt indoxyl vervolgens geheel omgezet tot indicaan. Het gevormde indicaan wordt opgeslagen. Bij beschadiging van de bladeren komt het enzym BGL vrij dat indicaan omzet tot indoxyl, waaruit vervolgens indigo ontstaat. Het enzym UGT bevindt zich op een andere plaats in de cel, waardoor UGT het gevormde indoxyl in deze situatie niet kan omzetten.$$, 'inline'),
  ('a2cd090a-d152-4c8d-bb8a-115c014dbfe9', '70be6b12-9de2-4133-b696-e1d12f4893d4', $$E. coli-experimenten met FMO/UGT-genen en BGL-enzym (premisse vraag 7)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2023-ii-indigo-context10.png$$,
   $$De onderzoekers kweekten enkele stammen van E. coli. In deze stammen waren wel of niet genen van de indigoplant overgebracht. In de tabel op de uitwerkbijlage is te zien welke experimenten zijn uitgevoerd. Bij elk experiment bevatte de voeding glucose en tryptofaan. Tryptofaan wordt door E. coli van nature omgezet tot indool. De bacteriën hebben geen genen voor de aanmaak van het enzym BGL. Om toch blauwkleuring mogelijk te maken, werd aan sommige bacteriekweken het enzym BGL toegevoegd. Niet in alle experimenten werd blauwkleuring door de vorming van indigo waargenomen.$$, 'inline'),
  ('66458ef4-0bb3-40e4-afea-258958ecd5d6', '70be6b12-9de2-4133-b696-e1d12f4893d4', $$uitwerkbijlage vraag 7 — tabel experimenten 1 t/m 4$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2023-ii-indigo-context11.png$$,
   $$uitwerkbijlage bij vraag 7: tabel met vier experimenten (1, 2, 3, 4). Rij 'stam bevat het gen voor FMO': nee, ja, ja, ja. Rij 'stam bevat het gen voor UGT': nee, nee, ja, ja. Rij 'enzym BGL toegevoegd': nee, nee, nee, ja. Rij 'blauwkleuring': voor elk experiment moet de kandidaat 'wel' of 'niet' invullen.$$, 'uitwerkbijlage'),
  ('439c024f-b03d-4789-9cb7-8dc155933c97', '2241dc06-c71d-496e-8c4f-5272e4ad280d', $$gifblaar en fluorethaanzuur — figuur 1 (structuurformule)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2023-ii-gifblaar-context1.png$$,
   $$In Zuid-Afrika groeit de gifblaar, een plant die giftig is voor veel dieren. In 1944 slaagde de Zuid-Afrikaanse onderzoeker Marais erin de gifstof uit deze plant te isoleren: fluorethaanzuur (zie figuur 1). Om de molecuulformule van de gifstof te bepalen, gebruikte Marais onder andere een element-analyse.

figuur 1: structuurformule van fluorethaanzuur — H₃C(F)–COOH, weergegeven als H–C(H)(F)–C(=O)OH.$$, 'inline'),
  ('71b53677-a260-4ee9-a4a3-2423241111b7', '2241dc06-c71d-496e-8c4f-5272e4ad280d', $$omzetting fluorethaanzuur tot calciumfluorethanoaat$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2023-ii-gifblaar-context2.png$$,
   $$Bij een van de proeven werd hiervoor het fluorethaanzuur met behulp van een calciumhydroxide-oplossing omgezet tot de geconjugeerde base fluorethanoaat. Bij indampen ontstond hieruit calciumfluorethanoaat.$$, 'inline'),
  ('4502b9eb-aae7-4762-b42d-7485ea3dcf81', '2241dc06-c71d-496e-8c4f-5272e4ad280d', $$LD50-waarde fluorethaanzuur bij konijnen — F-gehalte gedroogd blad$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2023-ii-gifblaar-context3.png$$,
   $$Marais bepaalde ook de LD50-waarde van fluorethaanzuur bij konijnen door ze gedroogde bladeren van de gifblaar te voeren. De LD50-waarde is de dosis waarbij 50% van de dieren die eraan zijn blootgesteld, sterft. Deze dosis bedroeg 0,40 mg fluorethaanzuur per kg lichaamsgewicht. Het blad van de gifblaar bevat gemiddeld 90 µg F per g gedroogd blad. Dit fluor is uitsluitend aanwezig in fluorethaanzuur.$$, 'inline'),
  ('9dd3b77e-1170-458e-8909-c5d955398411', '2241dc06-c71d-496e-8c4f-5272e4ad280d', $$Peters — citroenzuurcyclus en fluorethaanzuur, figuur 2$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2023-ii-gifblaar-context4.png$$,
   $$De Engelse onderzoeker R.A. Peters heeft rond 1950 baanbrekend onderzoek gedaan naar de biochemische werking van fluorethaanzuur. Hij ontdekte dat de citroenzuurcyclus niet meer functioneert in cellen waaraan fluorethaanzuur is toegevoegd. In figuur 2 is een gedeelte van de gewone citroenzuurcyclus schematisch weergegeven.

figuur 2: oxaalazijnzuur reageert (via citraat-synthase, met acetyl–S–CoA als reactant en HS–CoA als product) tot citroenzuur.$$, 'inline'),
  ('7cb555c9-e2ec-4edf-b1f5-569117c99792', '2241dc06-c71d-496e-8c4f-5272e4ad280d', $$acetyl–S–CoA, thio-estergroep en vorming fluorcitroenzuur$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2023-ii-gifblaar-context5.png$$,
   $$Acetyl–S–CoA is ontstaan door een condensatiereactie van co-enzym A (HS–CoA) met ethaanzuur. Een SH-groep van co-enzym A wordt hierbij omgezet tot een zogeheten thio-estergroep. Een thio-estergroep is vergelijkbaar met een gewone estergroep, waarin het enkelgebonden O-atoom is vervangen door een S-atoom. Peters ontdekte dat fluorethaanzuur de plaats inneemt van ethaanzuur in de citroenzuurcyclus, waardoor fluoracetyl–S–CoA wordt gevormd. In de volgende stap van de citroenzuurcyclus wordt fluoracetyl–S–CoA door het enzym citraat-synthase met oxaalazijnzuur omgezet tot fluorcitroenzuur (C₆H₇FO₇).$$, 'inline'),
  ('46df312b-99c3-4638-9793-259fc353073f', '2241dc06-c71d-496e-8c4f-5272e4ad280d', $$aconitase — stap 1, 2, 3 (fluorcitroenzuur naar trans-hydroxyaconietzuur)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2023-ii-gifblaar-context6.png$$,
   $$Na de vorming van fluorcitroenzuur treden in het actieve centrum van het enzym aconitase de volgende processen na elkaar op:
stap 1: Een molecuul fluorcitroenzuur wordt omgezet tot een molecuul water en een molecuul fluor-cis-aconietzuur.
stap 2: Vervolgens roteert het molecuul fluor-cis-aconietzuur 180° in het actieve centrum.
stap 3: Daarna wordt het molecuul fluor-cis-aconietzuur met een molecuul water omgezet tot een molecuul trans-hydroxyaconietzuur.$$, 'inline'),
  ('1e6f7c5e-8eb9-4cfd-ac7a-0ceafab2ccb2', '2241dc06-c71d-496e-8c4f-5272e4ad280d', $$trans-hydroxyaconietzuur blijft gebonden — trans-configuratie COOH-groepen$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2023-ii-gifblaar-context7.png$$,
   $$Het trans-hydroxyaconietzuur kan niet meer loskomen uit het actieve centrum, waardoor de stofwisseling van een dier dat de plant eet, wordt ontregeld. In een molecuul trans-hydroxyaconietzuur staan de COOH-groepen in een trans-configuratie ten opzichte van elkaar. Op de uitwerkbijlage is de omzetting van fluor-cis-aconietzuur volgens stap 3 onvolledig weergegeven.$$, 'inline'),
  ('2139b68d-2a54-49c0-8ceb-d82d257a5fa5', '2241dc06-c71d-496e-8c4f-5272e4ad280d', $$uitwerkbijlage vraag 11 — omzetting fluor-cis-aconietzuur (stap 3) naar trans-hydroxyaconietzuur$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2023-ii-gifblaar-context8.png$$,
   $$uitwerkbijlage bij vraag 11: bovenin, in een omkaderd deel, de structuurformule van fluor-cis-aconietzuur na rotatie (C³ met H, F en HOOC-substituenten, C² met COOH, C¹ met H en COOH, dubbele binding C¹=C²) plus een los watermolecuul H₂O — hierin moet de kandidaat met vloeipijlen de verplaatsing van elektronenparen aangeven. Onderaan, na de pijl 'stap 3' met daarbij H⁺ + F⁻, de structuurformule van trans-hydroxyaconietzuur met een dubbele binding C=C, een COOH-groep aan het linker C-atoom, en rechts een C-atoom met H, OH en COOH — de ontbrekende atomen/atoomgroepen (H en OH aan het rechter C-atoom) moet de kandidaat nog intekenen.$$, 'uitwerkbijlage'),
  ('c4121c6d-612e-4454-92c1-8dd749314f0f', '2241dc06-c71d-496e-8c4f-5272e4ad280d', $$actieve centrum aconitase — Fe₄S₄²⁺-cluster, figuur 3$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2023-ii-gifblaar-context9.png$$,
   $$In het actieve centrum van aconitase is een kubusvormig cluster met de formule Fe₄S₄²⁺ gebonden aan de peptideketen. In figuur 3 is dit cluster schematisch weergegeven, waarbij ladingen zijn weggelaten.

figuur 3: kubusvormig cluster met op de hoekpunten afwisselend vier Fe-atomen (Fe(a), Fe(b), Fe(c), Fe(d)) en vier S-atomen, onderling verbonden tot een kubus.$$, 'inline'),
  ('01d060bc-9604-4bfc-ae89-6cfad0cb8480', '2241dc06-c71d-496e-8c4f-5272e4ad280d', $$ladingen ijzerionen en sulfide-ionen — gebruikelijke ladingen$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2023-ii-gifblaar-context10.png$$,
   $$Het cluster Fe₄S₄²⁺ is opgebouwd uit ijzerionen en sulfide-ionen. De ladingen van de aanwezige ijzerionen en de sulfide-ionen wijken niet af van de gebruikelijke ladingen.$$, 'inline'),
  ('9413b1d0-8b42-4f94-a08b-23fb9a044c14', '2241dc06-c71d-496e-8c4f-5272e4ad280d', $$Fe(c) en Fe(d) gebonden aan cysteïne-eenheden — peptidefragment ~Cys–Gly–Pro–Cys~$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2023-ii-gifblaar-context11.png$$,
   $$De ijzerionen Fe(c) en Fe(d) zijn gebonden aan de peptideketen van aconitase via cysteïne-eenheden. Hierbij is de S–H-binding vervangen door een S–Fe-binding. De cysteïne-eenheden die binden aan Fe(c) en Fe(d) maken deel uit van het peptidefragment ~Cys–Gly–Pro–Cys~.$$, 'inline'),
  ('b988accb-d69b-41ac-b76f-7e6506bca40f', 'fac26e6d-5770-4593-b042-ec3c4658245a', $$Teflon — polymeer van tetrafluoretheen$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2023-ii-pfoa-context1.png$$,
   $$Teflon™ wordt onder andere gebruikt voor anti-aanbakpannen. Het is een polymeer van tetrafluoretheen.$$, 'inline'),
  ('29ead507-020e-4d10-bc38-81348d137b90', 'fac26e6d-5770-4593-b042-ec3c4658245a', $$productie PFOA uit octaanzuurfluoride — figuur 1 (blokschema reactor 1 en 2)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2023-ii-pfoa-context2.png$$,
   $$Bij de productie van Teflon™ wordt perfluoroctaanzuur (PFOA) gebruikt als hulpstof. PFOA (C₇F₁₅COOH) behoort tot de zogenoemde poly- en perfluoralkylstoffen (PFAS). Deze groep stoffen wordt toegepast in allerlei industriële processen en producten. PFOA wordt geproduceerd uit octaanzuurfluoride in twee reactoren. De omzettingen in deze reactoren zijn vereenvoudigd weergegeven in figuur 1.

figuur 1: C₇H₁₅–C(=O)–F (octaanzuurfluoride) → (reactor 1) → C₇F₁₅–C(=O)–F (stof P) → (reactor 2) → C₇F₁₅–C(=O)–OH (PFOA).$$, 'inline'),
  ('f479aea2-4677-4eaf-ac3b-f76e35a6fc71', 'fac26e6d-5770-4593-b042-ec3c4658245a', $$reactor 1 — elektrochemische cel, halfreactie 1$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2023-ii-pfoa-context3.png$$,
   $$Reactor 1 is een elektrochemische cel. Aan de positieve elektrode treedt halfreactie 1 op, waarbij telkens een waterstofatoom van octaanzuurfluoride wordt vervangen door een fluoratoom.

halfreactie 1: ∼C–H + HF → ∼C–F + 2 H⁺ + 2 e⁻$$, 'inline'),
  ('a586744c-6a03-4bfa-b1af-aacc355a7c94', 'fac26e6d-5770-4593-b042-ec3c4658245a', $$proces R1/S1/R2 — scheiding en doorvoer naar PFOA (premisse vraag 16 en 17)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2023-ii-pfoa-context4.png$$,
   $$De omzetting van octaanzuurfluoride tot PFOA is vereenvoudigd en onvolledig met een blokschema weergegeven op de uitwerkbijlage.
− In reactor 1 (R1) reageren octaanzuurfluoride en HF. Aan de positieve elektrode wordt stof P gevormd en aan de negatieve elektrode wordt waterstof gevormd uit H⁺-ionen.
− Waterstof verlaat R1 samen met een lage concentratie HF. De waterstof wordt in scheidingsruimte 1 (S1) gescheiden van HF met behulp van water.
− Als alle octaanzuurfluoride heeft gereageerd, wordt stof P doorgevoerd naar reactor 2 (R2). Hier reageren stof P en water volledig tot PFOA en HF, die als afzonderlijke stofstromen de reactor verlaten.
De instroom in R1 is op de uitwerkbijlage al volledig gegeven.$$, 'inline'),
  ('9a20302f-85c3-44fb-bfa2-d517b20da92c', 'fac26e6d-5770-4593-b042-ec3c4658245a', $$uitwerkbijlage vraag 17 — blokschema S1 en R1$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2023-ii-pfoa-context5.png$$,
   $$uitwerkbijlage bij vraag 17: blokschema met scheidingsruimte S1 (instroom van links, uitstroom naar rechts en een uitstroom naar boven) en daaronder reactor R1 (instroom C₇H₁₅COF van links en HF van onderen, uitstroom naar rechts en naar boven richting S1). De kandidaat moet reactor R2 tekenen en de ontbrekende pijlen met stofnamen aanvullen.$$, 'uitwerkbijlage'),
  ('6e6bd29e-4291-4000-a055-4c16cd34d6b8', 'fac26e6d-5770-4593-b042-ec3c4658245a', $$PFOA als zwak zuur — Kz-waarde$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2023-ii-pfoa-context6.png$$,
   $$PFOA is een zwak zuur met een Kz-waarde van 3,2·10⁻³. PFOA is daarom in water vooral aanwezig in de vorm van de geconjugeerde base C₇F₁₅COO⁻. Dit PFOA⁻ is goed oplosbaar in water.$$, 'inline'),
  ('1ac0b371-7b97-4835-95b1-9a9dd62f74f6', 'fac26e6d-5770-4593-b042-ec3c4658245a', $$PFOA in milieu — massaspectrum, figuur 2$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2023-ii-pfoa-context7.png$$,
   $$Wetenschappelijk onderzoek heeft aangetoond dat PFOA een risico vormt voor de gezondheid en het milieu. Het gebruik van PFOA is in Nederland sinds 2020 verboden voor consumentenproducten. Omdat PFOA slecht afbreekbaar is, is deze stof nog wel aanwezig in ons milieu. Voor de bepaling van de hoeveelheid PFOA in water of grond wordt onder andere gebruikgemaakt van massaspectrometrie. Een deel van het massaspectrum van PFOA (414 g mol⁻¹) is in figuur 2 weergegeven.

figuur 2: massaspectrum van PFOA, intensiteit (%) tegen m/z. Pieken bij m/z = 45 (~62%), 69 (~50%), 100 (~19%), 119 (~19%), 131 (100%), 169 (~10%), 181 (~10%), 219 (~8%), 231 (~9%).$$, 'inline'),
  ('df13185a-0c30-4a32-8a3f-d76083f5cb28', 'fac26e6d-5770-4593-b042-ec3c4658245a', $$fragmentatie PFOA — neutraal fragment Y (m/z 231 → 181)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2023-ii-pfoa-context8.png$$,
   $$Bij de gebruikte techniek neemt een molecuul PFOA een elektron op. Het gevormde [C₇F₁₅COOH]⁻ fragmenteert vervolgens. Uit het massaspectrum kan worden opgemaakt dat bij de fragmentatie van PFOA onder andere enkele malen hetzelfde neutrale fragment Y wordt afgesplitst. Zo is het fragment behorend bij de piek van m/z = 181 ontstaan uit het fragment behorend bij de piek van m/z = 231.$$, 'inline'),
  ('c0ded858-600d-4e89-a94f-75391825965a', 'dae87b66-71b1-4a2b-bb51-fa4bf00c800f', $$vonkremmend gas, doorslagspanning en ionisatie$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2023-ii-vonkremmers-context1.png$$,
   $$Bij hoogspanningsschakelaars en windturbines ontstaan er soms grote vonken als de stroom wordt in- en uitgeschakeld. Deze vonken geven storingen op het elektriciteitsnet en kunnen apparatuur beschadigen. Daarom zitten de contactpunten van dergelijke schakelaars in een behuizing die gevuld is met een vonkremmend gas. Een vonkremmend gas heeft een hoge doorslagspanning, dat is de spanning waarbij geleiding optreedt (bij bepaalde druk). De geleiding treedt op omdat bij hoge spanning gasmoleculen (X) bij de contactpunten geïoniseerd raken volgens X(g) + e⁻ → X⁺(g) + 2 e⁻. Bij lage druk is de doorslagspanning groot.$$, 'inline'),
  ('8387a177-3502-4600-b385-7b0846ba129c', 'dae87b66-71b1-4a2b-bb51-fa4bf00c800f', $$zwavelhexafluoride — proces 1 (elementen) versus proces 2$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2023-ii-vonkremmers-context2.png$$,
   $$Een veel toegepast vonkremmend gas is zwavelhexafluoride (SF₆). Dit gas wordt industrieel geproduceerd uit de elementen zwavel en fluor (proces 1). Fluor (F₂) is een giftig en agressief gas. Onderzoekers hebben daarom een andere syntheseroute ontwikkeld (proces 2). De reacties van proces 2 verlopen bij aanzienlijk lagere temperatuur dan bij proces 1.$$, 'inline'),
  ('3c5d2e95-1a07-49c8-bd3c-05ae8fcfc9b9', 'dae87b66-71b1-4a2b-bb51-fa4bf00c800f', $$proces 2 — reactie 1, 2 en 3$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2023-ii-vonkremmers-context3.png$$,
   $$In proces 2 treden drie reacties op:

reactie 1: 4 KF + S + 2 Br₂ → SF₄ + 4 KBr
reactie 2: SF₄ + 2 CoF₃ → SF₆ + 2 CoF₂
reactie 3: 2 CoF₂ + F₂ → 2 CoF₃$$, 'inline'),
  ('fd382662-f20d-4eb9-9898-5c8e097e9d63', 'dae87b66-71b1-4a2b-bb51-fa4bf00c800f', $$netto geen CoF3-verbruik — vormingswarmte SF6$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2023-ii-vonkremmers-context4.png$$,
   $$In proces 2 wordt netto geen CoF₃ verbruikt. De vormingswarmte van SF₆ is –12,25·10⁵ J mol⁻¹.$$, 'inline'),
  ('42098864-dc95-4ddf-b213-0e90dc38cd30', 'dae87b66-71b1-4a2b-bb51-fa4bf00c800f', $$brochure-stelling over groene chemie (premisse vraag 22)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2023-ii-vonkremmers-context5.png$$,
   $$In een brochure staat: “Dit alternatieve proces voldoet beter aan de uitgangspunten van groene chemie dan het standaard industriële proces.”$$, 'inline'),
  ('6778775c-2433-4db3-a279-f82108b850d4', 'dae87b66-71b1-4a2b-bb51-fa4bf00c800f', $$Novec 4710 als alternatief voor SF6 — beginstoffen en groepsverandering$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2023-ii-vonkremmers-context6.png$$,
   $$Zwavelhexafluoride is niet giftig, maar het is wel een sterk broeikasgas. Het is mogelijk om zwavelhexafluoride in hoogspanningsschakelaars te vervangen door andere stoffen, zoals Novec™ 4710 (C₄F₇N). Deze stof wordt in enkele stappen gemaakt. In het totale proces zijn de beginstoffen hierbij methylpropaanzuur, HF en NH₃. De andere stoffen die worden gevormd, zijn waterstof en water. Bij de omzettingen blijft het koolstofskelet gelijk, maar wordt de COOH-groep omgezet tot een CN-groep.$$, 'inline'),
  ('bcf87988-d0f7-4363-8825-4783788de893', 'dae87b66-71b1-4a2b-bb51-fa4bf00c800f', $$ontleding Novec 4710 tot de elementen — vormingswarmte en energiediagrammen P/Q/R/S$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2023-ii-vonkremmers-context7.png$$,
   $$In experimenten met zuiver Novec™ 4710 werd de spanning op de contactpunten zo hoog opgevoerd, dat er toch een elektrische ontlading plaatsvond in de schakelaar. Het bleek dat hierbij ontleding van Novec™ 4710 tot de elementen optreedt. Deze reactie treedt pas op bij zeer hoge waardes van de toegevoerde energie. De vormingswarmte van Novec™ 4710 is –33·10⁵ J mol⁻¹. In de figuur zie je enkele mogelijke energiediagrammen van deze omzetting.

figuur: vier energiediagrammen (energie tegen reactieverloop), genaamd P, Q, R en S. P: kleine energiebarrière, eindproducten liggen duidelijk lager in energie dan de beginstoffen (exotherm, klein activeringsenergieverschil). Q: grote energiebarrière, eindproducten liggen duidelijk lager in energie dan de beginstoffen (exotherm, groot activeringsenergieverschil). R: kleine energiebarrière, eindproducten liggen iets hoger in energie dan de beginstoffen (endotherm, klein). S: grote energiebarrière, eindproducten liggen iets hoger in energie dan de beginstoffen (endotherm, groot).$$, 'inline'),
  ('cce1a736-d359-4a5e-873e-a5e8da9a9d11', 'dae87b66-71b1-4a2b-bb51-fa4bf00c800f', $$praktijkproef — 60 kg SF6 vervangen door 20,8 kg Novec 4710$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2023-ii-vonkremmers-context8.png$$,
   $$Een standaard schakelaar bevat 60 kg zuiver SF₆. In een praktijkproef konden vergelijkbare vonkremmende resultaten worden bereikt door een gasmengsel van stikstof en Novec™ 4710 te gebruiken met daarin 20,8 kg Novec™ 4710.$$, 'inline'),
  ('da6bbb23-345a-4bd8-8c1b-a29adfa11bd6', 'dae87b66-71b1-4a2b-bb51-fa4bf00c800f', $$definitie GWP (global warming potential)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2023-ii-vonkremmers-context9.png$$,
   $$De mate waarin een stof bijdraagt aan het versterkt broeikaseffect wordt uitgedrukt in de GWP (global warming potential). De GWP van een stof is gedefinieerd als het opwarmingsvermogen van 1,0 kg van de stof in vergelijking met 1,0 kg CO₂, berekend over een periode van 100 jaar.$$, 'inline'),
  ('c36de5b0-a32f-4bc5-b6d3-74a2ebce8785', 'dae87b66-71b1-4a2b-bb51-fa4bf00c800f', $$berekeningsmethode en GWP-waarden SF6 en Novec 4710$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2023-ii-vonkremmers-context10.png$$,
   $$Om te berekenen welke winst er wordt gehaald met het oog op het broeikaseffect, gaat men uit van een situatie waarbij alle gas uit de schakelaar ontsnapt. Hierbij wordt de bijdrage aan het broeikaseffect omgerekend naar overeenkomende massa CO₂-uitstoot. De GWP-waarde van SF₆ is 22 800 terwijl Novec™ 4710 een GWP-waarde van slechts 2100 heeft.$$, 'inline');

